 65→            fetchNextPage();
 66→        }
 67→
 68→    }, [hasNextPage, fetchNextPage, isFetchingNextPage, inView])
 69→
 70→    useEffect(() =>{
 71→        const scroll = () =>{
 72→            setShowHeaders(false)
 73→            if(timeOutRef.current){
 74→                clearTimeout(timeOutRef.current)
 75→            }
