181→                                    journal.journals.bookmark_count?.[0]?.count,
182→                                    journal.journals.users.badge
183→                                )}
184→                            />
185→                        )}
186→
187→                        <div className="card-content">
188→                            <div onClick={(e) => handleClick(
189→                                e,
190→                                journal.journals.content,
191→                                parsedContent.wholeText,
192→                                journal.journals.title,
193→                                journal.journals.user_id,
194→                                journal.journals.users.name,
195→                                journal.journals.users.image_url,
196→                                journal.journals.created_at,
197→                                journal.journals.id,
198→                                journal.has_liked,
199→                                journal.journals.comment_count[0]?.count,
200→                                journal.has_bookmarked,
201→                                journal.journals.like_count?.[0]?.count,
202→                                journal.journals.bookmark_count?.[0]?.count,
203→                                journal.journals.users.badge
204→                            )}
205→                                className="content-container">
206→
207→                                <div className='feed-text-content-container'>
208→                                    <div className='feed-title-content'>
209→                                        <h2 className="feed-title">{journal.journals.title.length > 55 ? `${journal.journals.title.substring(0, 55)}...` : journal.journals.title}</h2>
210→                                    </div>
211→                                    <p className="feed-text-content">{parsedContent.slicedText}</p>
212→                                </div>
213→                            </div>
214→                        </div>
215→
216→                        <div className="bookmark-card-footer">
217→                            <div className='user-info-child-container'>
218→                                <div onClick={(e) => handleclickUserProfile(e, user?.userData?.[0].id, journal.journals.user_id)} className={`user-avatar-container ${journal?.journals?.users?.badge === 'legend' ? 'avatar-ring-legend' : journal?.journals?.users?.badge === 'og' ? 'avatar-ring-og' : ''}`}>
219→                                    <img loading='lazy' src={journal?.journals?.users?.image_url || '/assets/profile.jpg'} className="user-info-avatar" alt={`${journal?.journals?.users?.name || "User"} profile picture`} />
220→                                </div>
221→                                <div onClick={(e) => handleclickUserProfile(e, user?.userData?.[0].id, journal.journals.user_id)} className="user-name-container">
222→                                    <p className="user-newsfeed-name">{journal?.journals?.users?.name}</p>
223→                                    <VerifiedBadge badge={journal?.journals?.users?.badge} size={14} />
224→                                </div>
225→                                <div className="name-info-separator">•</div>
226→                                <p className="user-post-date">{formatPostDate(journal.created_at)}</p>
227→                            </div>
228→
229→                            <div className="bookmark-card-footer-right">
230→                                <div className="reading-time-container">
231→                                    <p className="reading-time-text">{CalculateText(parsedContent.wholeText)}</p>
232→                                </div>
233→
234→                                <div className="user-post-settings">
235→                                    <svg onClick={(e) => handleClickBookmarkSettings(e, journal.journals.id)} xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M240-400q-33 0-56.5-23.5T160-480q0-33 23.5-56.5T240-560q33 0 56.5 23.5T320-480q0 33-23.5 56.5T240-400Zm240 0q-33 0-56.5-23.5T400-480q0-33 23.5-56.5T480-560q33 0 56.5 23.5T560-480q0 33-23.5 56.5T480-400Zm240 0q-33 0-56.5-23.5T640-480q0-33 23.5-56.5T720-560q33 0 56.5 23.5T800-480q0 33-23.5 56.5T720-400Z"/></svg>
236→                                    {bookmarkIdSettings === journal.journals.id && (
237→                                        <motion.div
238→                                        initial={{opacity:0 ,scale:0}}
239→                                        animate={{opacity:1, scale:1, transition: {type: "tween", duration: 0.3}}}
240→                                        exit={{opacity:0, scale:0, transition: {type: "tween", duration: 0.3}}}
241→                                        ref={modalRef}
242→                                        className="setting-modal"
243→                                        >
244→                                            <p>{journal.journals.title}</p>
245→                                        </motion.div>
246→                                    )}
247→                                </div>
248→                            </div>
249→                        </div>
250→
251→                    </motion.div>
252→                )
253→            })}
254→            <div ref={inviewRef} className='inview-container'>
255→                <MoonLoader loading={isFetchingNextPage} color="rgba(255, 255, 255, 0.64)" speedMultiplier={1} size={20}/>
256→            </div>
257→        </div>
258→        </>
259→    )
260→}
